{
  "query": "query locationInventoryLevels($id: ID!, $first: Int!, $after: String) { location(id: $id) { id name inventoryLevels(first: $first, after: $after) { edges { cursor node { item { id sku tracked } quantities(names: [\"available\", \"incoming\", \"reserved\", \"on_hand\"]) { name quantity } } } pageInfo { hasNextPage endCursor } } } }",
  "variables": {
    "id": "{{location_id}}",
    "first": {{first}},
    "after": {{after_cursor}}
  }
}

{
  "query": "mutation runInventoryItemsBulkExport { bulkOperationRunQuery(query: \"\"\"{ inventoryItems { edges { node { id sku inventoryLevels { edges { node { location { id name } quantities(names: [\\\"available\\\", \\\"incoming\\\", \\\"reserved\\\", \\\"on_hand\\\"]) { name quantity } } } } } } } }\"\"\") { bulkOperation { id status } userErrors { field message } } }"
}

{
  "query": "query currentBulkOperation { currentBulkOperation { id status errorCode createdAt completedAt objectCount fileSize url partialDataUrl } }"
}

{
  "query": "query inventoryTransfers($first: Int!, $query: String) { inventoryTransfers(first: $first, query: $query) { nodes { id name referenceName status dateCreated totalQuantity receivedQuantity lineItemsCount { count } } pageInfo { hasNextPage endCursor } } }",
  "variables": {
    "first": {{first}},
    "query": "{{transfer_query}}"
  }
}

{
  "query": "query inventoryTransfer($id: ID!, $lineItemFirst: Int!, $shipmentFirst: Int!) { inventoryTransfer(id: $id) { id name referenceName status dateCreated note tags totalQuantity receivedQuantity lineItemsCount { count } lineItems(first: $lineItemFirst) { nodes { id title totalQuantity processableQuantity shippableQuantity shippedQuantity inventoryItem { id sku } } } shipments(first: $shipmentFirst) { nodes { id name status dateCreated dateShipped dateReceived } } } }",
  "variables": {
    "id": "{{transfer_id}}",
    "lineItemFirst": {{line_item_first}},
    "shipmentFirst": {{shipment_first}}
  }
}

{
  "query": "query inventoryShipment($id: ID!, $lineItemFirst: Int!) { inventoryShipment(id: $id) { id name status dateCreated dateShipped dateReceived lineItemsCount { count } lineItemTotalQuantity totalAcceptedQuantity totalReceivedQuantity totalRejectedQuantity tracking { trackingNumber company trackingUrl arrivesAt } lineItems(first: $lineItemFirst) { nodes { id quantity acceptedQuantity rejectedQuantity unreceivedQuantity inventoryItem { id sku } } } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "lineItemFirst": {{line_item_first}}
  }
}

{
  "query": "mutation inventoryTransferCreate($input: InventoryTransferCreateInput!, $idempotencyKey: String!) { inventoryTransferCreate(input: $input) @idempotent(key: $idempotencyKey) { inventoryTransfer { id name referenceName status dateCreated } userErrors { field message } } }",
  "variables": {
    "input": {
      "originLocationId": "{{origin_location_id}}",
      "destinationLocationId": "{{destination_location_id}}",
      "lineItems": [
        {
          "inventoryItemId": "{{inventory_item_id}}",
          "quantity": {{inventory_item_quantity}}
        },
        {
          "inventoryItemId": "{{inventory_item_id_2}}",
          "quantity": {{inventory_item_quantity_2}}
        }
      ],
      "tags": [
        "postman",
        "transfer-test"
      ],
      "dateCreated": "{{date_created_datetime}}",
      "note": "{{note}}",
      "referenceName": "{{reference_name}}"
    },
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryTransferEdit($id: ID!, $input: InventoryTransferEditInput!) { inventoryTransferEdit(id: $id, input: $input) { inventoryTransfer { id name referenceName status note tags } userErrors { field message } } }",
  "variables": {
    "id": "{{transfer_id}}",
    "input": {
      "originId": "{{origin_location_id}}",
      "destinationId": "{{destination_location_id}}",
      "dateCreated": "{{date_created_date}}",
      "note": "{{note}}",
      "tags": [
        "postman",
        "edited"
      ],
      "referenceName": "{{reference_name}}"
    }
  }
}

{
  "query": "mutation inventoryTransferSetItems($input: InventoryTransferSetItemsInput!, $idempotencyKey: String!) { inventoryTransferSetItems(input: $input) @idempotent(key: $idempotencyKey) { inventoryTransfer { id status lineItemsCount { count } } updatedLineItems { inventoryItemId newQuantity } userErrors { field message code } } }",
  "variables": {
    "input": {
      "id": "{{transfer_id}}",
      "lineItems": [
        {
          "inventoryItemId": "{{inventory_item_id}}",
          "quantity": {{inventory_item_quantity_set}}
        },
        {
          "inventoryItemId": "{{inventory_item_id_2}}",
          "quantity": {{inventory_item_quantity_set_2}}
        }
      ]
    },
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryTransferRemoveItems($input: InventoryTransferRemoveItemsInput!) { inventoryTransferRemoveItems(input: $input) { inventoryTransfer { id status lineItemsCount { count } } removedQuantities { inventoryItemId newQuantity } userErrors { field message } } }",
  "variables": {
    "input": {
      "id": "{{transfer_id}}",
      "transferLineItemIds": [
        "{{transfer_line_item_id}}"
      ]
    }
  }
}

{
  "query": "mutation inventoryTransferMarkAsReadyToShip($id: ID!) { inventoryTransferMarkAsReadyToShip(id: $id) { inventoryTransfer { id name referenceName status } userErrors { field message } } }",
  "variables": {
    "id": "{{transfer_id}}"
  }
}

{
  "query": "mutation inventoryShipmentCreate($input: InventoryShipmentCreateInput!, $idempotencyKey: String!) { inventoryShipmentCreate(input: $input) @idempotent(key: $idempotencyKey) { userErrors { field message code } inventoryShipment { id name status dateCreated } } }",
  "variables": {
    "input": {
      "movementId": "{{transfer_id}}",
      "lineItems": [
        {
          "inventoryItemId": "{{inventory_item_id}}",
          "quantity": {{shipment_item_quantity}}
        }
      ]
    },
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryShipmentAddItems($id: ID!, $lineItems: [InventoryShipmentLineItemInput!]!, $idempotencyKey: String!) { inventoryShipmentAddItems(id: $id, lineItems: $lineItems) @idempotent(key: $idempotencyKey) { userErrors { field message code } inventoryShipment { id name status } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "lineItems": [
      {
        "inventoryItemId": "{{inventory_item_id_2}}",
        "quantity": {{shipment_item_quantity_2}}
      }
    ],
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryShipmentUpdateItemQuantities($id: ID!, $items: [InventoryShipmentUpdateItemQuantitiesInput!]) { inventoryShipmentUpdateItemQuantities(id: $id, items: $items) { shipment { id name status } updatedLineItems { id quantity acceptedQuantity rejectedQuantity unreceivedQuantity } userErrors { field message } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "items": [
      {
        "shipmentLineItemId": "{{shipment_line_item_id}}",
        "quantity": {{shipment_item_quantity_update}}
      }
    ]
  }
}

{
  "query": "mutation inventoryShipmentRemoveItems($id: ID!, $lineItems: [ID!]!) { inventoryShipmentRemoveItems(id: $id, lineItems: $lineItems) { inventoryShipment { id name status } userErrors { field message } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "lineItems": [
      "{{shipment_line_item_id_2}}"
    ]
  }
}

{
  "query": "mutation inventoryShipmentSetTracking($id: ID!, $tracking: InventoryShipmentTrackingInput!) { inventoryShipmentSetTracking(id: $id, tracking: $tracking) { inventoryShipment { id name status tracking { trackingNumber company trackingUrl arrivesAt } } userErrors { field message } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "tracking": {
      "trackingNumber": "{{tracking_number}}",
      "company": "{{tracking_company}}",
      "trackingUrl": "{{tracking_url}}",
      "arrivesAt": "{{tracking_arrives_at}}"
    }
  }
}

{
  "query": "mutation inventoryShipmentMarkInTransit($id: ID!, $dateShipped: DateTime) { inventoryShipmentMarkInTransit(id: $id, dateShipped: $dateShipped) { inventoryShipment { id name status dateShipped } userErrors { field message } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "dateShipped": "{{date_shipped}}"
  }
}

{
  "query": "mutation inventoryShipmentReceive($id: ID!, $lineItems: [InventoryShipmentReceiveItemInput!], $idempotencyKey: String!) { inventoryShipmentReceive(id: $id, lineItems: $lineItems) @idempotent(key: $idempotencyKey) { userErrors { field message } inventoryShipment { id name status dateReceived } } }",
  "variables": {
    "id": "{{shipment_id}}",
    "lineItems": [
      {
        "shipmentLineItemId": "{{shipment_line_item_id}}",
        "quantity": {{shipment_receive_quantity}},
        "reason": "{{shipment_receive_reason}}"
      }
    ],
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryTransferCreateAsReadyToShip($input: InventoryTransferCreateAsReadyToShipInput!, $idempotencyKey: String!) { inventoryTransferCreateAsReadyToShip(input: $input) @idempotent(key: $idempotencyKey) { inventoryTransfer { id name referenceName status dateCreated } userErrors { field message } } }",
  "variables": {
    "input": {
      "originLocationId": "{{origin_location_id}}",
      "destinationLocationId": "{{destination_location_id}}",
      "lineItems": [
        {
          "inventoryItemId": "{{inventory_item_id}}",
          "quantity": {{inventory_item_quantity}}
        },
        {
          "inventoryItemId": "{{inventory_item_id_2}}",
          "quantity": {{inventory_item_quantity_2}}
        }
      ],
      "tags": [
        "postman",
        "ready-to-ship"
      ],
      "dateCreated": "{{date_created_datetime}}",
      "note": "{{note}}",
      "referenceName": "{{reference_name}}"
    },
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryShipmentCreateInTransit($input: InventoryShipmentCreateInput!, $idempotencyKey: String!) { inventoryShipmentCreateInTransit(input: $input) @idempotent(key: $idempotencyKey) { userErrors { field message code } inventoryShipment { id name status dateCreated dateShipped } } }",
  "variables": {
    "input": {
      "movementId": "{{transfer_id}}",
      "lineItems": [
        {
          "inventoryItemId": "{{inventory_item_id}}",
          "quantity": {{shipment_item_quantity}}
        }
      ]
    },
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryTransferDuplicate($id: ID!, $idempotencyKey: String!) { inventoryTransferDuplicate(id: $id) @idempotent(key: $idempotencyKey) { inventoryTransfer { id name referenceName status } userErrors { field message } } }",
  "variables": {
    "id": "{{transfer_id}}",
    "idempotencyKey": "{{$guid}}"
  }
}

{
  "query": "mutation inventoryTransferCancel($id: ID!) { inventoryTransferCancel(id: $id) { inventoryTransfer { id name referenceName status } userErrors { field message } } }",
  "variables": {
    "id": "{{transfer_id}}"
  }
}
